SELECT COUNT(*) AS qtd_servidores FROM servidor s WHERE LOWER(s.contrato) = LOWER('efetivos') AND LOWER(s.area_ingresso) = LOWER('geografia') AND LOWER(s.sigla_campus) = LOWER('val') AND s.saiu_do_ifg = FALSE AND EXISTS (SELECT 1 FROM calc_hora_aula_media c WHERE c.siape = s.pk_siape AND c.ano = 2024 AND c.semestre = 1 AND LOWER(c.sigla_campus) = LOWER('val') AND LOWER(c.area_ingresso) = LOWER('geografia'))